mapper.select:
/* Comu.selectComuListForBo */ SELECT C.ID AS comuId, C.COMU_TYPE AS comuType, CD_CODE.CODE_NM AS comuTypeName, C.EVENT_ID AS orderId, O.ORDER_NO AS orderNo, O.CRE_TM AS orderDate, P.PAYMENT_STATUS AS paymentStatus, FN_GET_CODE('10070', P.PAYMENT_STATUS) AS paymentStatusName, FN_GET_TOP_PRODUCT_NAME(O.ID) AS topProductName, LAST_MSG.COMU_CNTN AS lastMessage, LAST_MSG.CRE_TM AS lastMessageTm, UNREAD.cntCntn AS cntCntn, C.CRE_TM AS creTm FROM TB_COMU C LEFT JOIN TB_CODE CD_CODE ON CD_CODE.CODE_UPPER = '10130' AND CD_CODE.CODE_CD = C.COMU_TYPE AND CD_CODE.DEL_YN = 'N' LEFT JOIN TB_ORDER O ON O.ID = C.EVENT_ID LEFT JOIN TB_PAYMENT P ON P.ORDER_ID = O.ID AND P.DEL_YN = 'N' LEFT JOIN LATERAL ( SELECT COMU_CNTN, CRE_TM FROM TB_COMU_DET WHERE COMU_ID = C.ID AND DEL_YN = 'N' ORDER BY ID DESC LIMIT 1 ) LAST_MSG ON TRUE LEFT JOIN LATERAL ( SELECT CONCAT(SUM(CASE WHEN READ_YN = 'N' THEN 1 ELSE 0 END), ' / ' ,COUNT(ID)) AS cntCntn FROM TB_COMU_DET WHERE COMU_ID = C.ID AND DEL_YN = 'N' AND REQ_YN = 'Y' ) UNREAD ON TRUE WHERE C.DEL_YN = 'N'
AND C.COMU_TYPE = #{comuType}
AND P.PAYMENT_STATUS = #{paymentStatus}
AND EXISTS ( SELECT 1 FROM TB_ORDER_ITEM OI2 WHERE OI2.ORDER_ID = O.ID AND OI2.PRODUCT_NAME ILIKE '%' || #{productName} || '%' )
AND O.CRE_TM >= #{fromDate}
AND O.CRE_TM < #{toDate}
ORDER BY LAST_MSG.CRE_TM ASC

mapper.update:
/* Comu.updateReadYnByComuId */
UPDATE TB_COMU_DET SET
    READ_YN = 'Y'
WHERE COMU_ID = #{comuId}
  AND REQ_YN  = #{reqYn}
  AND DEL_YN  = 'N'
  AND READ_YN = 'N'

/* Comu.deleteComuDet */
UPDATE TB_COMU_DET SET
    DEL_YN = 'Y'
WHERE ID = #{id}

mapper.select:
/* Comu.selectCodeDesc */
SELECT CODE_DESC
FROM TB_CODE
WHERE CODE_UPPER = #{codeUpper}
  AND CODE_CD    = #{codeCd}
  AND DEL_YN     = 'N'
LIMIT 1

/* Comu.selectCodeNm */
SELECT CODE_NM
FROM TB_CODE
WHERE CODE_UPPER = #{codeUpper}
  AND CODE_CD    = #{codeCd}
  AND DEL_YN     = 'N'
LIMIT 1
